import React, { useEffect } from "react";
import { DndProvider } from "react-dnd";
import { HTML5Backend } from "react-dnd-html5-backend";
import DraggableItem from "./DraggableItem";
import DropBox from "./DropBox";
import { startTracking, getData } from "./tracker";
import axios from "axios";

function AnimalGame({ onNext }) {
  useEffect(() => {
    startTracking();
  }, []);

  const finishGame = async () => {
    const data = getData();

    await axios.post("http://localhost:5000/save", {
      studentId: "child_01",
      activity: "animal_drag_game",
      ...data,
    });

    if (onNext) onNext();
  };

  return (
    <DndProvider backend={HTML5Backend}>
      <div style={{ textAlign: "center", background: "#E0FFFF", height: "100vh" }}>
        <h1>Match Animals 🐾</h1>

        <div style={{ display: "flex", justifyContent: "center" }}>
          <DraggableItem name="dog" emoji="🐶" />
          <DraggableItem name="cat" emoji="🐱" />
        </div>

        <div style={{ display: "flex", justifyContent: "center" }}>
          <DropBox acceptName="dog" label="Dog 🐕" />
          <DropBox acceptName="cat" label="Cat 🐈" />
        </div>

        <button onClick={finishGame} style={{ fontSize: "20px" }}>
          Next ➡️
        </button>
      </div>
    </DndProvider>
  );
}

export default AnimalGame;
